export const validatePsalmBriefs = () => {
  const errors = [];
  const lloydJonesPsalms = new Set([1,7,8,14,16,23,27,37,42,43,44,50,51,63,73,76,77,78,81,84,103,106,116,119]);
  const stottPsalms = new Set(psalmsWithStottCoverage);
  const promptPatterns = [
    new RegExp(["Analyze specific", "Hebrew poetry"].join(" "), "i"),
    new RegExp("^\\s*\\(" + ["BULLET", "POINTS"].join(" ") + "\\)\\s*$", "i"),
    new RegExp("^\\s*\\(" + ["MUST", "begin"].join(" "), "i"),
  ];
  const scanText = (psalm, cardTitle, value) => {
    if (typeof value !== 'string') return;
    value.split(/\n/).forEach((line) => {
      if (promptPatterns.some((pattern) => pattern.test(line))) {
        errors.push(`Psalm ${psalm} ${cardTitle} contains a leftover prompt instruction.`);
      }
    });
  };

  for (let psalm = 1; psalm <= 150; psalm += 1) {
    const brief = psalmBriefs[psalm];
    if (!brief) {
      errors.push(`Psalm ${psalm} is missing.`);
      continue;
    }
    if (!Array.isArray(brief.cards) || brief.cards.length !== REQUIRED_CARD_TITLES.length) {
      errors.push(`Psalm ${psalm} must have exactly ${REQUIRED_CARD_TITLES.length} cards.`);
      continue;
    }
    REQUIRED_CARD_TITLES.forEach((title, index) => {
      if (brief.cards[index]?.title !== title) {
        errors.push(`Psalm ${psalm} card ${index + 1} must be ${title}.`);
      }
    });
    brief.cards.forEach((card) => {
      scanText(psalm, card.title, card.content);
      (card.items || []).forEach((item) => scanText(psalm, card.title, typeof item === 'string' ? item : item?.text));
    });
    const insights = brief.cards.find((card) => card.title === 'Scholarly Voices');
    const items = insights?.items || [];
    const hasKeller = items.some((item) => item && typeof item === 'object' && item.source === 'Timothy Keller' && item.text?.trim());
    const hasLloyd = items.some((item) => item && typeof item === 'object' && item.source === 'D. Martyn Lloyd-Jones' && item.text?.trim());
    const motyerItems = items.filter((item) => item && typeof item === 'object' && item.source === 'Alec Motyer' && item.text?.trim());
    const stottItems = items.filter((item) => item && typeof item === 'object' && item.source === 'John Stott' && item.text?.trim());
    if (!hasKeller) errors.push(`Psalm ${psalm} must include a Timothy Keller Scholarly Voices insight.`);
    if (lloydJonesPsalms.has(psalm) && !hasLloyd) errors.push(`Psalm ${psalm} must include a D. Martyn Lloyd-Jones Scholarly Voices insight.`);
    if (!lloydJonesPsalms.has(psalm) && hasLloyd) errors.push(`Psalm ${psalm} should not include a D. Martyn Lloyd-Jones insight without indexed coverage.`);
    if (motyerItems.length !== 1) errors.push(`Psalm ${psalm} must include exactly one Alec Motyer Scholarly Voices insight.`);
    if (stottPsalms.has(psalm) && stottItems.length !== 1) errors.push(`Psalm ${psalm} must include exactly one John Stott Scholarly Voices insight.`);
    if (!stottPsalms.has(psalm) && stottItems.length) errors.push(`Psalm ${psalm} should not include John Stott without selected-psalm coverage.`);
  }
  return errors;
};
